import React, { useEffect, useState } from "react";
import { useSearchParams, Link } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import { verifyB2bPayment } from "../../features/b2b/b2bSlice";
import { getSocket } from "../../socket";
import B2bLayout from "./B2bLayout";
import { CheckCircle2, XCircle, Loader2, ArrowRight, Package, CreditCard } from "lucide-react";

const B2bPaymentSuccess = () => {
  const [searchParams] = useSearchParams();
  const dispatch = useDispatch();
  const txRef = searchParams.get("trx_ref") || searchParams.get("tx_ref") || searchParams.get("transaction_id") || "";

  const { paymentResult, isPaying, isError, message } = useSelector((s) => s.b2b);
  const [verified, setVerified] = useState(false);
  const [failed, setFailed] = useState(false);

  useEffect(() => {
    if (txRef && !verified && !failed) {
      dispatch(verifyB2bPayment(txRef))
        .unwrap()
        .then(() => setVerified(true))
        .catch(() => setFailed(true));
    }
  }, [dispatch, txRef, verified, failed]);

  // Listen for real-time payment confirmation
  useEffect(() => {
    const socket = getSocket();
    if (!socket) return;
    const handleVerified = (payload) => {
      if (payload?.order?.txRef === txRef) {
        setVerified(true);
      }
    };
    socket.on("b2b:payment:verified", handleVerified);
    return () => socket.off("b2b:payment:verified", handleVerified);
  }, [txRef]);

  const order = paymentResult?.data;
  const orderId = order?.id;

  return (
    <B2bLayout>
      <div className="flex items-center justify-center min-h-[60vh]">
        <div className="w-full max-w-lg">
          {/* Verifying */}
          {isPaying && !verified && !failed && (
            <div className="bg-white rounded-3xl border border-slate-100 p-10 shadow-sm text-center">
              <div className="w-16 h-16 bg-indigo-50 rounded-2xl flex items-center justify-center mx-auto mb-6">
                <Loader2 size={32} className="text-indigo-600 animate-spin" />
              </div>
              <h1 className="text-xl font-black text-slate-900 mb-2">Verifying Payment...</h1>
              <p className="text-sm text-slate-500 font-medium">
                Please wait while we confirm your payment with Chapa.
              </p>
              <p className="text-[10px] text-slate-400 font-bold mt-4 uppercase tracking-widest">
                TX Ref: {txRef}
              </p>
            </div>
          )}

          {/* Success */}
          {verified && (
            <div className="bg-white rounded-3xl border border-slate-100 p-10 shadow-sm text-center">
              <div className="w-20 h-20 bg-emerald-50 rounded-3xl flex items-center justify-center mx-auto mb-6 border-2 border-emerald-100">
                <CheckCircle2 size={40} className="text-emerald-500" />
              </div>
              <h1 className="text-2xl font-black text-slate-900 mb-2">Payment Successful!</h1>
              <p className="text-sm text-slate-500 font-medium mb-6 leading-relaxed">
                Your payment has been verified and confirmed. Our operations team will process your procurement order shortly.
              </p>

              {order && (
                <div className="bg-slate-50 rounded-2xl p-5 mb-6 text-left space-y-3">
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-500 font-medium flex items-center gap-2">
                      <Package size={14} /> Order
                    </span>
                    <span className="font-extrabold text-slate-800">
                      {order.orderNumber || `ORD-${orderId?.slice(0, 8)}`}
                    </span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-500 font-medium flex items-center gap-2">
                      <CreditCard size={14} /> Amount Paid
                    </span>
                    <span className="font-extrabold text-slate-800">
                      {parseFloat(order.totalPrice || 0).toLocaleString()} ETB
                    </span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-500 font-medium">Status</span>
                    <span className="text-emerald-600 font-black text-xs uppercase bg-emerald-50 px-2 py-0.5 rounded-md border border-emerald-100">
                      PAID
                    </span>
                  </div>
                </div>
              )}

              <div className="flex flex-col gap-3">
                {orderId && (
                  <Link
                    to={`/b2b/orders/${orderId}`}
                    className="w-full h-12 bg-gradient-to-r from-indigo-600 to-violet-600 text-white rounded-2xl font-black uppercase tracking-wider text-sm flex items-center justify-center gap-2 hover:shadow-lg hover:shadow-indigo-200 transition-all"
                  >
                    View Order Details <ArrowRight size={16} />
                  </Link>
                )}
                <Link
                  to="/b2b/orders"
                  className="w-full h-12 bg-slate-100 text-slate-700 rounded-2xl font-bold text-sm flex items-center justify-center hover:bg-slate-200 transition-colors"
                >
                  All Procurement Orders
                </Link>
              </div>
            </div>
          )}

          {/* Failed */}
          {failed && (
            <div className="bg-white rounded-3xl border border-slate-100 p-10 shadow-sm text-center">
              <div className="w-20 h-20 bg-rose-50 rounded-3xl flex items-center justify-center mx-auto mb-6 border-2 border-rose-100">
                <XCircle size={40} className="text-rose-500" />
              </div>
              <h1 className="text-2xl font-black text-slate-900 mb-2">Payment Verification Failed</h1>
              <p className="text-sm text-slate-500 font-medium mb-3 leading-relaxed">
                We could not verify your payment. This may be a temporary issue — please check your order status or try again.
              </p>
              {message && (
                <p className="text-xs text-rose-600 font-bold bg-rose-50 rounded-xl p-3 mb-6">
                  {message}
                </p>
              )}
              <p className="text-[10px] text-slate-400 font-bold mb-6 uppercase tracking-widest">
                TX Ref: {txRef || "Not provided"}
              </p>
              <div className="flex flex-col gap-3">
                <Link
                  to="/b2b/orders"
                  className="w-full h-12 bg-slate-800 text-white rounded-2xl font-black uppercase tracking-wider text-sm flex items-center justify-center hover:bg-slate-900 transition-colors"
                >
                  View My Orders
                </Link>
                <Link
                  to="/b2b"
                  className="w-full h-12 bg-slate-100 text-slate-600 rounded-2xl font-bold text-sm flex items-center justify-center hover:bg-slate-200 transition-colors"
                >
                  Back to Catalog
                </Link>
              </div>
            </div>
          )}

          {/* No txRef */}
          {!txRef && !isPaying && !verified && !failed && (
            <div className="bg-white rounded-3xl border border-slate-100 p-10 shadow-sm text-center">
              <h1 className="text-xl font-black text-slate-900 mb-2">No Payment Reference</h1>
              <p className="text-sm text-slate-500 font-medium mb-6">
                No transaction reference was found. If you just completed a payment, please check your order history.
              </p>
              <Link
                to="/b2b/orders"
                className="inline-flex items-center gap-2 bg-blue-600 text-white px-6 py-3 rounded-2xl font-bold text-sm hover:bg-blue-700 transition-colors"
              >
                Go to Orders <ArrowRight size={16} />
              </Link>
            </div>
          )}
        </div>
      </div>
    </B2bLayout>
  );
};

export default B2bPaymentSuccess;
